on_write:
let res = #{ action: "Allow" };
if payload.contains("xml_body") && !payload.xml_body.starts_with("<") {
    res.action = "Reject";
    res.reason = "Native XML requires valid tag-based payloads";
}
res

on_read:
let res = #{ payload: payload };
// Simulate XPath tag presence check
if payload.xml_body.contains("<" + query_key + ">") {
    res.match_found = true;
} else {
    res.match_found = false;
}
res
